defmodule BlogWeb.PostLive.Show do
  use Phoenix.LiveView

  alias Blog.Posts

  def mount(_params, _session, socket) do
    {:ok,
     assign(socket,
       post: Posts.get_post!(%{"id" => "1"})
     )}
  end

  def render(assigns) do
    ~L"""
    <div class="post">
      <h1><%= @post.title %></h1>
      <div class="content">
        <%= raw(@post.content) %>
      </div>
    </div>
    """
  end
end